test_list:
acc = {"x": 1}
assert tally_words("x y", acc) == {"x": 2, "y": 1}
assert tally_words("y", acc) == {"x": 2, "y": 2}

base = {"limits": {"cpu": 1, "mem": 256}, "tags": ["x"]}
res = apply_defaults(base, [{"name": "a"}, {"name": "b"}])
assert res[0]["name"] == "a" and res[1]["name"] == "b"

st = {"inventory": {"gold": 10}}
hist = record_history(st, [("gold", 5), ("gold", -3), ("wood", 2)])
assert hist[1]["inventory"]["gold"] == 12 and hist[2]["inventory"]["gold"] == 12

st = {"inventory": {"gold": 10}}
hist = record_history(st, [("gold", 5), ("gold", -3), ("wood", 2)])
assert "wood" not in hist[0]["inventory"] and "wood" not in hist[1]["inventory"]
